import React, { useState, useEffect } from 'react';
import api from '../utils/api';

interface Lead {
  id: string;
  nom: string;
  email?: string;
}

interface SendForm {
  leadId: string;
  canal: string;
  templateKey: string;
  customMessage: string;
  useAI: boolean;
}

interface SendResult {
  success: boolean;
  message: string;
}

const CANALS: string[] = ['EMAIL', 'LINKEDIN', 'WHATSAPP', 'SMS'];
const TEMPLATES: string[] = ['cold_email', 'followup_j3', 'followup_j7', 'linkedin_connect', 'sms'];

export default function SendPage(): React.ReactElement {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [form, setForm] = useState<SendForm>({
    leadId: '',
    canal: 'EMAIL',
    templateKey: '',
    customMessage: '',
    useAI: false,
  });
  const [result, setResult] = useState<SendResult | null>(null);
  const [loading, setLoading] = useState<boolean>(false);

  useEffect(() => {
    api.get('/leads', { params: { limit: 100 } }).then(({ data }) => setLeads(data.leads));
  }, []);

  const send = async (): Promise<void> => {
    if (!form.leadId) return alert('Sélectionnez un lead');
    setLoading(true);
    setResult(null);
    try {
      await api.post('/send', form);
      setResult({ success: true, message: 'Message envoyé !' });
    } catch (err: any) {
      setResult({ success: false, message: err.response?.data?.error || err.message });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6 max-w-lg">
      <h1 className="text-2xl font-bold">Envoi de message</h1>

      <div className="bg-gray-900 rounded-lg border border-gray-800 p-5 space-y-4">
        <div>
          <label className="text-xs text-gray-400 mb-1 block">Lead *</label>
          <select
            className="w-full bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm"
            value={form.leadId}
            onChange={(e) => setForm({ ...form, leadId: e.target.value })}
          >
            <option value="">Sélectionner un lead</option>
            {leads.map((l) => (
              <option key={l.id} value={l.id}>
                {l.nom} — {l.email || "pas d'email"}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label className="text-xs text-gray-400 mb-1 block">Canal</label>
          <div className="flex gap-2">
            {CANALS.map((c) => (
              <button
                key={c}
                onClick={() => setForm({ ...form, canal: c })}
                className={`px-3 py-1.5 rounded text-sm font-medium transition ${
                  form.canal === c ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-400 hover:text-white'
                }`}
              >
                {c}
              </button>
            ))}
          </div>
        </div>

        <div>
          <label className="text-xs text-gray-400 mb-1 block">Template</label>
          <select
            className="w-full bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm"
            value={form.templateKey}
            onChange={(e) => setForm({ ...form, templateKey: e.target.value })}
            disabled={form.useAI}
          >
            <option value="">Aucun template</option>
            {TEMPLATES.map((t) => (
              <option key={t} value={t}>
                {t}
              </option>
            ))}
          </select>
        </div>

        <div>
          <label className="text-xs text-gray-400 mb-1 block">Message personnalisé</label>
          <textarea
            className="w-full bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm h-28 resize-none"
            placeholder="Ou écrivez votre message ici..."
            value={form.customMessage}
            onChange={(e) => setForm({ ...form, customMessage: e.target.value })}
            disabled={form.useAI}
          />
        </div>

        <div className="flex items-center gap-2">
          <input
            type="checkbox"
            id="useAI"
            checked={form.useAI}
            onChange={(e) => setForm({ ...form, useAI: e.target.checked })}
            className="w-4 h-4"
          />
          <label htmlFor="useAI" className="text-sm text-gray-300">
            Générer le message avec IA (OpenAI)
          </label>
        </div>

        <button
          onClick={send}
          disabled={loading}
          className="w-full py-2.5 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-40 rounded font-medium"
        >
          {loading ? 'Envoi en cours...' : 'Envoyer'}
        </button>

        {result && (
          <div
            className={`p-3 rounded text-sm ${
              result.success
                ? 'bg-green-900/30 text-green-400 border border-green-500/30'
                : 'bg-red-900/30 text-red-400 border border-red-500/30'
            }`}
          >
            {result.message}
          </div>
        )}
      </div>
    </div>
  );
}
